class DatabaseConnection:
    def __init__(self, dsn):
        self.dsn = dsn
        self._connection = None

    def connect(self):
        self._connection = f'Connected to {self.dsn}'
        return self

    def query(self, sql):
        return f'Executed: {sql}'

    def close(self):
        self._connection = None

